    LayerNormCustomTilingData tiling;

    // Input shapes
    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const gert::StorageShape *w_shape = context->GetInputShape(1);
    // weight is 1D, its total size equals hiddenSize
